import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
// Thêm các icon từ lucide-react để giao diện chuyên nghiệp hơn
import { Heart, ListPlus, Trash2, Play, Pause, SkipForward, SkipBack, Trophy } from 'lucide-react';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const audioRef = useRef(null);
  
  const navigate = useNavigate();
  const loggedInUser = JSON.parse(localStorage.getItem('user')); // Lấy user đang đăng nhập

  const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

  // 1. Tải danh sách nhạc
  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) {
      console.error("Lỗi tải danh sách nhạc:", err);
    }
  };

  useEffect(() => {
    fetchSongs();
  }, []);

  // 2. Chức năng LIKE (Favorite)
  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập để Like!");
    try {
      await axios.post('http://localhost:5000/api/songs/toggle-like', {
        songId: songId,
        userId: loggedInUser._id || loggedInUser.id
      });
      fetchSongs(); // Tải lại để cập nhật số lượt Like
    } catch (err) { console.error(err); }
  };

  // 3. Chức năng Admin Xóa bài
  const handleDelete = async (songId) => {
    if (window.confirm("Bạn có chắc muốn xóa bài hát này?")) {
      try {
        await axios.delete(`http://localhost:5000/api/songs/${songId}`);
        fetchSongs();
      } catch (err) { alert("Lỗi khi xóa bài"); }
    }
  };

  // Các hàm điều khiển nhạc giữ nguyên của bạn
  const playSong = (index) => { setCurrentIndex(index); setIsPlaying(true); };
  const nextSong = () => setCurrentIndex((currentIndex + 1) % songs.length);
  const prevSong = () => setCurrentIndex((currentIndex - 1 + songs.length) % songs.length);
  const togglePlay = () => {
    if (isPlaying) audioRef.current.pause();
    else audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  const formatTime = (time) => {
    if (isNaN(time)) return "0:00";
    const min = Math.floor(time / 60);
    const sec = Math.floor(time % 60);
    return `${min}:${sec < 10 ? '0' : ''}${sec}`;
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '150px', color: '#333' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h2 style={{ fontWeight: 'bold' }}>KHÁM PHÁ ÂM NHẠC</h2>
        <button 
          onClick={() => navigate('/ranking')} 
          style={{ display: 'flex', alignItems: 'center', gap: '5px', background: '#FFD700', border: 'none', padding: '8px 15px', borderRadius: '20px', cursor: 'pointer', fontWeight: 'bold' }}
        >
          <Trophy size={18} /> Bảng Xếp Hạng
        </button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '25px', marginTop: '20px' }}>
        {songs.map((song, index) => (
          <div key={song._id} style={cardStyle}>
            <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '10px' }}>
              <img src={`http://localhost:5000${song.imageUrl}`} style={{ width: '100%', height: '200px', objectFit: 'cover' }} alt="cover" />
              <button onClick={() => playSong(index)} style={hoverPlayBtn}>
                <Play fill="white" size={20} />
              </button>
              
              {/* Nút xóa cho ADMIN */}
              {loggedInUser?.role === 'admin' && (
                <button onClick={() => handleDelete(song._id)} style={adminDeleteBtn}>
                  <Trash2 size={16} />
                </button>
              )}
            </div>

            <h4 style={{ margin: '15px 0 5px 0', fontSize: '16px' }}>{song.title}</h4>
            <p style={{ fontSize: '14px', color: '#888', margin: '0' }}>{song.artist}</p>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '10px' }}>
               <div onClick={() => navigate(`/profile/${song.userId}`)} style={{ cursor: 'pointer', fontSize: '12px', color: '#1db954', fontWeight: 'bold' }}>
                 {song.uploaderName || "User"} 👤
               </div>
               
               <div style={{ display: 'flex', gap: '10px' }}>
                 {/* Nút LIKE */}
                 <button onClick={() => handleLike(song._id)} style={actionBtn}>
                   <Heart size={18} color={song.likes?.includes(loggedInUser?._id || loggedInUser?.id) ? 'red' : '#888'} fill={song.likes?.includes(loggedInUser?._id || loggedInUser?.id) ? 'red' : 'none'} />
                   <span style={{ fontSize: '12px' }}>{song.likes?.length || 0}</span>
                 </button>
                 {/* Nút PLAYLIST */}
                 <button style={actionBtn}><ListPlus size={18} /></button>
               </div>
            </div>
          </div>
        ))}
      </div>

      {/* PLAYER NHẠC (Giữ logic cũ, thay icon) */}
      {currentSong && (
        <div style={playerContainerStyle}>
          <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
            <img src={`http://localhost:5000${currentSong.imageUrl}`} style={{ width: '55px', height: '55px', borderRadius: '5px', marginRight: '15px' }} alt="" />
            <div>
              <div style={{ fontWeight: 'bold' }}>{currentSong.title}</div>
              <div style={{ fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</div>
            </div>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
              <SkipBack onClick={prevSong} style={{ cursor: 'pointer' }} />
              <button onClick={togglePlay} style={btnMain}>
                {isPlaying ? <Pause size={24} /> : <Play size={24} />}
              </button>
              <SkipForward onClick={nextSong} style={{ cursor: 'pointer' }} />
            </div>
            <div style={{ display: 'flex', alignItems: 'center', width: '100%', gap: '10px', marginTop: '5px' }}>
              <span style={{ fontSize: '11px' }}>{formatTime(currentTime)}</span>
              <input type="range" min="0" max={duration || 0} value={currentTime} onChange={(e) => audioRef.current.currentTime = e.target.value} style={{ flex: 1, accentColor: '#1db954' }} />
              <span style={{ fontSize: '11px' }}>{formatTime(duration)}</span>
            </div>
            <audio ref={audioRef} src={`http://localhost:5000${currentSong.songUrl}`} autoPlay onEnded={nextSong} onTimeUpdate={() => setCurrentTime(audioRef.current.currentTime)} onLoadedMetadata={() => setDuration(audioRef.current.duration)} />
          </div>
          <div style={{ width: '30%' }}></div>
        </div>
      )}
    </div>
  );
};

